// RMSNorm is row-local, so the host launcher only dispatches this variant when
// each hidden row fits evenly inside one QR tile. For Qwen3.5 hidden_dim=4096
// bf16 rows, one 32 KiB QR tile contains four independent rows.
template <typename T, typename CommT, class Codec, bool cast_bf2half = false>
struct AllReduceTwoshotRMSNorm
{
    static_assert(sizeof(T) == 2);
    static_assert(sizeof(CommT) == 2);

    static constexpr int kWorldSize = Codec::kWorldSize;
    static constexpr int kElemsPerAtom = sizeof(int32x4_t) / sizeof(T);

    __device__ static void run(T const* __restrict__ input,
                               T const* __restrict__ residual_inp,
                               T* __restrict__ residual_out,
                               T* __restrict__ output,
                               T const* __restrict__ weight,
                               float eps,
                               uint32_t const N,
                               uint32_t const hidden_dim,
                               int const block,
                               int const rank,
                               uint8_t** __restrict__ buffer_list,
                               uint32_t const data_offset,
                               uint32_t flag_color,
                               int64_t data_size_per_phase)
    {
        int thread           = threadIdx.x + threadIdx.y * kWavefront;
        uint8_t* rank_buffer = buffer_list[rank];
        Codec codec(thread, rank);
        int block_id = blockIdx.x;
        uint8_t* buffer_ptr[kWorldSize];
        for(int i = 0; i < kWorldSize; ++i)
        {
            buffer_ptr[i] = buffer_list[i];
        }

        // --------------------------------------------------------
        // Read input into registers, converting to the communication type when
        // the bf16 input is intentionally reduced through fp16 QR kernels.
        int32x4_t tA[kAtoms];

        BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
        uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            int32x4_t raw = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
            if constexpr(std::is_same<T, CommT>::value)
            {
                tA[i] = raw;
            }
            else
            {
                int32x4_t comm_pack;
                CommT* comm_vals = reinterpret_cast<CommT*>(&comm_pack);
                const T* raw_vals = reinterpret_cast<const T*>(&raw);
#pragma unroll
                for(int j = 0; j < kElemsPerAtom; ++j)
                {
                    comm_vals[j] = qr_from_float<CommT>(qr_to_float<T>(raw_vals[j]));
                }
                tA[i] = comm_pack;
            }
            src_offset += kAtomStride * sizeof(int32x4_t);
        }

        // --------------------------------------------------------
        // Phase-1A: Write segment data into the communication buffer of the
        // target rank responsible for this segment.
        uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
        uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;

        uint32_t comm_flags0_offset = block_id * (kWorldSize * sizeof(uint32_t));
        uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags0_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // --------------------------------------------------------
        // Phase-1B: Reduce the segment data from the communication buffers.
        int32x4_t tR[Codec::kRankAtoms] = {};
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, tA);

                for(int i = 0; i < Codec::kRankAtoms; i++)
                {
                    packed_assign_add<CommT>(&tR[i], &tA[i]);
                }
            }
        }

        // --------------------------------------------------------
        // Phase-2A: Write the reduced segment to every rank.
        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, tR);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags1_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // --------------------------------------------------------
        // Phase-2B: Gather all reduced rank segments into tA.
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
            }
        }

        // --------------------------------------------------------
        // Fused add-residual + RMSNorm epilogue. The launcher guarantees that
        // hidden rows divide the QR tile, so no row crosses this workgroup.
        static constexpr uint32_t kTileElems = kTileSize / sizeof(T);
        __shared__ float row_smem[kBlockSize];

        int32x4_t tX[kAtoms];
        BufferResource residual_in_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
        BufferResource residual_out_buffer(residual_out, N * sizeof(T));
        BufferResource output_buffer(output, N * sizeof(T));
        BufferResource weight_buffer(const_cast<T*>(weight), hidden_dim * sizeof(T));

        uint32_t elem_tile_base = block * kTileElems;
        uint32_t byte_offset    = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            int32x4_t residual_pack =
                buffer_load_dwordx4(residual_in_buffer.descriptor, byte_offset, 0, 0);

            const CommT* ar_vals = reinterpret_cast<const CommT*>(&tA[i]);
            const T* residual_vals = reinterpret_cast<const T*>(&residual_pack);
            T* x_vals = reinterpret_cast<T*>(&tX[i]);
#pragma unroll
            for(int j = 0; j < kElemsPerAtom; ++j)
            {
                float x = qr_to_float<CommT>(ar_vals[j]) + qr_to_float<T>(residual_vals[j]);
                x_vals[j] = qr_from_float<T>(x);
            }

            buffer_store_dwordx4(tX[i], residual_out_buffer.descriptor, byte_offset, 0, 0);
            byte_offset += kAtomStride * sizeof(int32x4_t);
        }

        uint32_t packs_per_row = hidden_dim / kElemsPerAtom;
        uint32_t rows_per_tile = kTileElems / hidden_dim;

        for(uint32_t row = 0; row < rows_per_tile; ++row)
        {
            uint32_t global_row_start = elem_tile_base + row * hidden_dim;
            float square_sum = 0.0f;

            if(global_row_start < N)
            {
                for(int i = 0; i < kAtoms; i++)
                {
                    uint32_t tile_pack = i * kBlockSize + thread;
                    uint32_t pack_row  = tile_pack / packs_per_row;
                    if(pack_row == row)
                    {
                        const T* x_vals = reinterpret_cast<const T*>(&tX[i]);
#pragma unroll
                        for(int j = 0; j < kElemsPerAtom; ++j)
                        {
                            float x = qr_to_float<T>(x_vals[j]);
                            square_sum += x * x;
                        }
                    }
                }
            }

            for(int offset = kWavefront / 2; offset > 0; offset >>= 1)
            {
                square_sum += __shfl_down(square_sum, offset);
            }

            int lane = thread & (kWavefront - 1);
            int wave = thread / kWavefront;
            if(lane == 0)
            {
                row_smem[wave] = square_sum;
            }
            __syncthreads();

            float block_sum = thread < (kBlockSize / kWavefront) ? row_smem[thread] : 0.0f;
            for(int offset = kWavefront / 2; offset > 0; offset >>= 1)
            {
                block_sum += __shfl_down(block_sum, offset);
            }
            if(thread == 0)
            {
                row_smem[0] = block_sum;
            }
            __syncthreads();

            float denom = rsqrtf(row_smem[0] / static_cast<float>(hidden_dim) + eps);

            if(global_row_start < N)
            {
                for(int i = 0; i < kAtoms; i++)
                {
                    uint32_t tile_pack = i * kBlockSize + thread;
                    uint32_t pack_row  = tile_pack / packs_per_row;
                    if(pack_row == row)
                    {
                        uint32_t col_pack = tile_pack - pack_row * packs_per_row;
                        uint32_t col      = col_pack * kElemsPerAtom;
                        int32x4_t weight_pack = buffer_load_dwordx4(
                            weight_buffer.descriptor, col * sizeof(T), 0, 0);
                        int32x4_t out_pack;
                        const T* x_vals = reinterpret_cast<const T*>(&tX[i]);
                        const T* weight_vals = reinterpret_cast<const T*>(&weight_pack);
                        T* out_vals = reinterpret_cast<T*>(&out_pack);
#pragma unroll
                        for(int j = 0; j < kElemsPerAtom; ++j)
                        {
                            float x = qr_to_float<T>(x_vals[j]);
                            float w = qr_to_float<T>(weight_vals[j]);
                            out_vals[j] = qr_from_float<T>(x * denom * w);
                        }

                        uint32_t out_byte_offset =
                            block * kTileSize + tile_pack * sizeof(int32x4_t);
                        buffer_store_dwordx4(
                            out_pack, output_buffer.descriptor, out_byte_offset, 0, 0);
                    }
                }
            }
            __syncthreads();
        }
    }
};


